+// AGGREGATE and EXTEND are ordinary identifiers outside a pipe query. Once they
+// follow |>, however, they are pipe clause names. GROUP BY is similarly special
+// only inside an AGGREGATE pipe step.
+function detectPipeClauses(tokens: Token[]): Token[] {
+  let previous: Token | undefined;
+  let inAggregatePipe = false;
+
+  return tokens.map(token => {
+    if (token.type === TokenType.PIPE) {
+      previous = token;
+      inAggregatePipe = false;
+      return token;
+    }
+
+    let processed = token;
+    if (previous?.type === TokenType.PIPE && (token.text === 'AGGREGATE' || token.text === 'EXTEND')) {
+      processed = { ...token, type: TokenType.RESERVED_CLAUSE, text: token.text.toUpperCase() };
+      inAggregatePipe = processed.text === 'AGGREGATE';
+    } else if (inAggregatePipe && token.type === TokenType.RESERVED_CLAUSE && token.text === 'GROUP BY') {
+      processed = { ...token, type: TokenType.PIPE_GROUP_BY };
+    }
+
+    previous = processed;
+    return processed;
+  });
